def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        elif ratio == 1:
            priorities[i] = 0
            continue
        score = 0
        for j in range(1, 21):
            if j % 3 == 0:
                term = ((-1) ** (j+1)) * ((ratio ** j) / (j ** 1.5))
            elif j % 2 == 0:
                term = (ratio ** j) / (j * np.log(j+1))
            else:
                term = -((ratio ** j) / (j))
            score += term
        adjustment = 1.0
        if capacity < item * 1.2:
            adjustment *= 2.5
        elif capacity < item * 1.5:
            adjustment *= 2.0
        elif capacity < item * 2:
            adjustment *= 1.7
        elif capacity < item * 3:
            adjustment *= 1.3
        penalty = 0
        window = 5
        start_idx = max(0, i - window)
        end_idx = min(n, i + window + 1)
        for k in range(start_idx, end_idx):
            if k == i or bins[k] == 0:
                continue
            overlap_ratio = item / bins[k]
            if 0 < overlap_ratio < 1:
                penalty += ((1 - overlap_ratio) ** 2) * ((window - abs(k - i)) / window)
        penalty /= (window * 2)
        score = -score * adjustment + penalty
        if score < 0:
            score = 0
        noise = np.sin(i * 3.14 / n) * 0.05
        score += noise
        if score > 1:
            score = 1
        priorities[i] = score
    return priorities
